var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"검은 범람 발생 14시간 경과","JPN":"黒い氾濫の発生から14時間経過","ENG":"14 hours since the Black Flood onset","TWN":"黑色洪災發生14小時後","DEU":"14 hours since the Black Flood onset","FRA":"14 hours since the Black Flood onset"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"섬 주민들을 흔쾌히 태워주셔서 감사해요.","JPN":"快くの島の住民たちを乗せてくださって、ありがとうございます。","ENG":"Thank you for taking in our islanders without hesitation.","TWN":"謝謝妳毫不猶豫地接納島上的居民。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"그러니까…….","JPN":"ええと……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"메리 크루.","JPN":"メリー・クルー。","ENG":"Mary Crew.","TWN":"瑪麗·克盧。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"지금은 메리 크루라고 불러주는 게 좋겠구나.","JPN":"今はメリー・クルーと呼んでちょうだい。","ENG":"For now, it's best if you call me Mary Crew.","TWN":"現在就叫我瑪麗·克盧吧。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"에이버리 해적단의 메리 리드는… 이미 바닷속에 잠들어 있으니 말이다.","JPN":"エイバリー海賊団のメリー・リードは……海の底で眠りについたからね。","ENG":"Mary Read of the Avery Pirates... is already resting beneath the sea.","TWN":"艾維利海盜團的瑪麗·里德……已經沉入海底了。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그리고 다른 아이들에겐…….","JPN":"それから、他の子たちには……","ENG":"And for the others...","TWN":"至於其他孩子們……"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"네. 알고 있어요.","JPN":"はい、わかっています。","ENG":"Yes. I know.","TWN":"嗯，我知道。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"조심하도록 할게요.","JPN":"気をつけます。","ENG":"I'll be careful.","TWN":"我會小心的。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"도와줘서 고마워, 아줌마.","JPN":"助けてくれてありがとう、おばさん。","ENG":"Thanks for helping, Auntie Mary.","TWN":"謝謝妳幫忙，阿姨。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"후후, 뛰어난 사냥꾼을 데려온 덕분이란다.","JPN":"ふふ、優秀な狩人を連れてきた甲斐があったね。","ENG":"Fufu, you brought quite the impressive hunter with you.","TWN":"呵呵，多虧我帶了一位出色的獵手。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"망설임 없이 사냥감을 향해 송곳니를 꽂는 그 움직임.","JPN":"迷わず獲物に向かって牙を突き刺すあの動き。","ENG":"The way she sank her fangs into her prey without a hint of hesitation...","TWN":"那毫不猶豫撲咬獵物的動作，"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"자신이 뭐를 위해 싸우는지 잘 아는 것 같은 모습이었단다.","JPN":"自分が何のために戦っているのか、よくわかっている動きだった。","ENG":"She fights knowing exactly what she's fighting for.","TWN":"讓人覺得她很清楚自己為了什麼而戰。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"뭐를 위해서… 싸우는 지?","JPN":"何のために……戦っているのか？","ENG":"What she's... fighting for?","TWN":"為了什麼……而戰？"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그래. 너에게 한 번쯤은 소개해 주고 싶을 정도로 목적이 확실했지.","JPN":"そう。一度あなたに紹介してあげたいと思ったほど、目的がはっきりしていたわ。","ENG":"Yes. Clear enough that I'd introduce her to you at least once.","TWN":"是啊。她的目標明確到我好想介紹給妳。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"네 소식은 아주 잘 들려오더구나.","JPN":"あなたの近況は、よく耳に入ってきていたよ。","ENG":"I've heard plenty about you.","TWN":"我一直都有收到妳的消息。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"자유를 위해… 관리국을 뒤엎으려 했다지?","JPN":"自由のために……管理局を倒そうとしたのね？","ENG":"You tried to topple the Administration... all for freedom, I hear?","TWN":"妳為了自由……想要推翻管理局，對吧？"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"아직도 그 생각은 변함이 없니?","JPN":"その考えは、今も変わらない？","ENG":"Do you still feel the same way?","TWN":"妳還沒改變那個想法嗎？"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"하지만 키이라.","JPN":"でもね、キーラさん。","ENG":"But Kiera.","TWN":"但是琪伊拉，"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"때론 사람은 상식적으로 이해할 수 없는 행동을 하기도 해요.","JPN":"時に人は、常識では理解できない行動をしたりもします。","ENG":"Sometimes people act in ways that defy reason.","TWN":"有時候人也會做出無法用常理解釋的行動。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"예를 들면, 내가 평생을 바쳐 번 돈으로 산 집,","JPN":"例えば、自分が一生稼いだお金で買った家、","ENG":"Like the home I worked my whole life to build,","TWN":"例如，用一生積蓄買下的房子、"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"내 유년 시절을 바친 고향,","JPN":"自分の幼い時代を捧げた故郷、","ENG":"the hometown that holds every memory of my childhood...","TWN":"寄託童年時光的故鄉、"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"혹은 그냥 이곳의 분위기, 냄새, 사람들…… 그런 것들이 좋아서 자유를 내던지는 사람들이 많죠.","JPN":"あるいはただここの雰囲気、匂い、人々……そんなものが好きで自由を犠牲にする人もいるのです。","ENG":"or even just the feel of this place, its scent, its voices... Some people give up their freedom for things like that.","TWN":"又或者只是不知為何喜歡這裡的氛圍、味道、以及這裡的人們……也有很多因為這些理由而放棄自由的人。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"20년 전, 갑작스레 일어난 검은 범람에 휘말린 우리 섬을 구해준…….","JPN":"20年前、突然と発生した黒い氾濫に巻き込まれた私たちの島を助けてくれた……","ENG":"Just like the Avery Pirates did...","TWN":"20年前，拯救這座被突如其來的黑色洪災襲擊的島嶼的……"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"에이버리 해적단처럼 말이에요.","JPN":"エイバリー海賊団のように。","ENG":"when they saved our island twenty years ago, during the Black Flood.","TWN":"就是艾維利海盜團。"},"stage":{"bg":"FRONTBAY_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"잘… 모르겠어.","JPN":"よく……わかんない。","ENG":"I... still don't really know.","TWN":"我……不知道。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};